-- ============================================================
-- 3. ASISTENCIA
-- ============================================================
DROP TABLE IF EXISTS `asistencia`;
CREATE TABLE `asistencia` (
  `id`                int          NOT NULL AUTO_INCREMENT,
  `empleado_id`       int          NOT NULL,
  `fecha`             date         NOT NULL,
  `hora_entrada`      time         DEFAULT NULL,
  `hora_salida`       time         DEFAULT NULL,
  `minutos_retraso`   int          DEFAULT '0',
  `diferencia_salida` int          DEFAULT '0',
  `estado`            varchar(50)  DEFAULT 'Sin registro',
  `puerta`            varchar(60)  DEFAULT NULL,
  `sucursal`          varchar(60)  DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `empleado_id` (`empleado_id`,`fecha`),
  CONSTRAINT `asistencia_ibfk_1` FOREIGN KEY (`empleado_id`) REFERENCES `empleados` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

