-- ============================================================
-- 4. NOVEDADES
-- ============================================================
DROP TABLE IF EXISTS `novedades`;
CREATE TABLE `novedades` (
  `id`           int          NOT NULL AUTO_INCREMENT,
  `empleado_id`  int          NOT NULL,
  `tipo_novedad` enum('Permiso Personal','Vacaciones','Incapacidad Medica') NOT NULL,
  `fecha_inicio` date         NOT NULL,
  `fecha_fin`    date         NOT NULL,
  `notas`        text,
  `estado`       enum('Pendiente','Aprobado','Rechazado') DEFAULT 'Aprobado',
  PRIMARY KEY (`id`),
  KEY `empleado_id` (`empleado_id`),
  CONSTRAINT `novedades_ibfk_1` FOREIGN KEY (`empleado_id`) REFERENCES `empleados` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

