-- ============================================================
-- 5. BIOMETRIA_FACIAL
-- ============================================================
DROP TABLE IF EXISTS `biometria_facial`;
CREATE TABLE `biometria_facial` (
  `id`                  int       NOT NULL AUTO_INCREMENT,
  `empleado_id`         int       NOT NULL,
  `face_embedding`      json      NOT NULL,
  `fecha_enrolamiento`  datetime  DEFAULT CURRENT_TIMESTAMP,
  `fecha_actualizacion` datetime  DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `activo`              tinyint(1) DEFAULT '1',
  PRIMARY KEY (`id`),
  UNIQUE KEY `empleado_id` (`empleado_id`),
  KEY `idx_empleado_activo` (`empleado_id`,`activo`),
  CONSTRAINT `biometria_facial_ibfk_1` FOREIGN KEY (`empleado_id`) REFERENCES `empleados` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci
  COMMENT='Biometría facial — exclusivamente vectores numéricos. Política: cero almacenamiento de imágenes.';

